                              NETWORKS[networkKey]?.erc20Precompile 
                                ? 'grid-cols-1 sm:grid-cols-2' 
                                : 'grid-cols-1'
                            }`}>
                              <select
                                value={newToken[networkKey]?.standard || 'ERC20'}
                                onChange={(e) => setNewToken(prev => ({
                                  ...prev,
                                  [networkKey]: { ...prev[networkKey], standard: e.target.value }
