                                  ...prev,
                                  [networkKey]: {
                                    ...prev[networkKey],
                                    ...result.bridgeConfig,
                                    key: generatedKey,
                                    alreadyExists: bridgeExists,
                                    needsUpdate: needsUpdate,
                                    fieldDifferences: fieldDifferences,
                                    upToDate: bridgeExists && !needsUpdate
                                  }
                                }));

